"use client";

import * as React from "react";
import {
  Stepper,
  type StepperStep,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Button,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  Input,
  PasswordInput,
  Select,
  RadioGroup,
  RadioGroupItem,
  Checkbox,
  Switch,
  Textarea,
  Alert,
  AlertTitle,
  AlertDescription,
  Badge,
  Separator,
} from "@gunjo/ui";
import { IconPencil } from "@tabler/icons-react";

/* ------------------------------------------------------------------ */
/* Types & constants                                                  */
/* ------------------------------------------------------------------ */

type StepIndex = 0 | 1 | 2 | 3;

const STEP_TITLES = ["アカウント", "組織", "設定", "確認"];
const STEP_DESCRIPTIONS = [
  "あなたについて教えてください。",
  "会社についての基本情報を入力します。",
  "ワークスペースの使い方を選びます。",
  "内容を確認して、ワークスペースを作成します。",
];

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const PASSWORD_MIN = 8;

const COMPANY_SIZES = [
  { value: "1-10", label: "1〜10名" },
  { value: "11-50", label: "11〜50名" },
  { value: "51-200", label: "51〜200名" },
  { value: "201-1000", label: "201〜1000名" },
  { value: "1000+", label: "1000名以上" },
];

const INDUSTRIES = [
  { value: "software", label: "ソフトウェア・IT" },
  { value: "finance", label: "金融" },
  { value: "healthcare", label: "ヘルスケア" },
  { value: "education", label: "教育" },
  { value: "retail", label: "小売・EC" },
  { value: "manufacturing", label: "製造" },
  { value: "other", label: "その他" },
];

const FREQUENCIES = [
  { value: "realtime", label: "リアルタイム", hint: "できごとが起きたらすぐに通知します。" },
  { value: "daily", label: "毎日まとめて", hint: "1日1回、サマリーをメールでお送りします。" },
  { value: "weekly", label: "毎週まとめて", hint: "週に1回、サマリーをメールでお送りします。" },
  { value: "off", label: "オフ", hint: "通知メールを送信しません。" },
];

type FormState = {
  fullName: string;
  email: string;
  password: string;
  company: string;
  companySize: string;
  industry: string;
  productUpdates: boolean;
  betaFeatures: boolean;
  shareUsage: boolean;
  frequency: string;
  goals: string;
  agreeTerms: boolean;
};

const initialForm: FormState = {
  fullName: "",
  email: "",
  password: "",
  company: "",
  companySize: "",
  industry: "",
  productUpdates: true,
  betaFeatures: false,
  shareUsage: false,
  frequency: "daily",
  goals: "",
  agreeTerms: false,
};

type Errors = Partial<Record<keyof FormState, string>>;

/* ------------------------------------------------------------------ */
/* Validation                                                         */
/* ------------------------------------------------------------------ */

/** Returns errors for the fields owned by a given step. */
function validateStep(step: StepIndex, form: FormState): Errors {
  const e: Errors = {};
  if (step === 0) {
    if (!form.fullName.trim()) e.fullName = "氏名を入力してください。";
    if (!form.email.trim()) e.email = "仕事用のメールアドレスを入力してください。";
    else if (!EMAIL_RE.test(form.email.trim()))
      e.email = "有効なメールアドレスを入力してください（例：you@company.com）。";
    if (!form.password) e.password = "パスワードを入力してください。";
    else if (form.password.length < PASSWORD_MIN)
      e.password = `パスワードは${PASSWORD_MIN}文字以上で入力してください。`;
  }
  if (step === 1) {
    if (!form.company.trim()) e.company = "会社名を入力してください。";
    if (!form.companySize) e.companySize = "会社規模を選択してください。";
    if (!form.industry) e.industry = "業種を選択してください。";
  }
  // Step 2 (Preferences) has no required fields.
  if (step === 3) {
    if (!form.agreeTerms) e.agreeTerms = "続けるには規約への同意が必要です。";
  }
  return e;
}

/** DOM id (in source order) of the first field with an error, for focus-move. */
function firstErrorFieldId(step: StepIndex, errors: Errors): string | null {
  const order: Record<StepIndex, (keyof FormState)[]> = {
    0: ["fullName", "email", "password"],
    1: ["company", "companySize", "industry"],
    2: [],
    3: ["agreeTerms"],
  };
  for (const key of order[step]) {
    if (errors[key]) return `field-${key}`;
  }
  return null;
}

/* ------------------------------------------------------------------ */
/* Field shell — wires label / error / aria together                 */
/* ------------------------------------------------------------------ */

function FieldShell({
  id,
  label,
  required,
  description,
  error,
  children,
}: {
  id: string;
  label: string;
  required?: boolean;
  description?: string;
  error?: string;
  children: (a: {
    id: string;
    labelId: string;
    /** Spreadable aria props — safe to apply directly to a form control. */
    aria: {
      id: string;
      "aria-invalid": boolean | undefined;
      "aria-describedby": string | undefined;
      "aria-required": boolean | undefined;
    };
  }) => React.ReactNode;
}) {
  const descId = description ? `${id}-desc` : undefined;
  const errId = error ? `${id}-error` : undefined;
  const labelId = `${id}-label`;
  const describedBy = [descId, errId].filter(Boolean).join(" ") || undefined;

  return (
    <FormField className="p-0">
      <FormLabel id={labelId} htmlFor={id}>
        {label}
        {required ? (
          <span className="ml-0.5 text-destructive" aria-hidden="true">
            *
          </span>
        ) : null}
      </FormLabel>
      {description ? (
        <FormDescription id={descId}>{description}</FormDescription>
      ) : null}
      <FormControl>
        {children({
          id,
          labelId,
          aria: {
            id,
            "aria-invalid": error ? true : undefined,
            "aria-describedby": describedBy,
            "aria-required": required || undefined,
          },
        })}
      </FormControl>
      {error ? (
        <FormMessage id={errId} role="alert">
          {error}
        </FormMessage>
      ) : null}
    </FormField>
  );
}

/* ------------------------------------------------------------------ */
/* Page                                                               */
/* ------------------------------------------------------------------ */

export default function SetupWizardPage() {
  const [step, setStep] = React.useState<StepIndex>(0);
  const [form, setForm] = React.useState<FormState>(initialForm);
  const [touched, setTouched] = React.useState<Partial<Record<keyof FormState, boolean>>>({});
  // Per-step "Next was attempted" flag → reveal all errors for that step.
  const [attempted, setAttempted] = React.useState<Record<StepIndex, boolean>>({
    0: false,
    1: false,
    2: false,
    3: false,
  });
  const [submitted, setSubmitted] = React.useState(false);
  const [stepAnnounce, setStepAnnounce] = React.useState("");

  const set = <K extends keyof FormState>(key: K, value: FormState[K]) =>
    setForm((f) => ({ ...f, [key]: value }));

  const markTouched = (key: keyof FormState) =>
    setTouched((t) => ({ ...t, [key]: true }));

  const stepErrors = validateStep(step, form);

  /** Should a field's error be shown? Only after it's touched OR Next attempted. */
  const showError = (key: keyof FormState): string | undefined => {
    if (!stepErrors[key]) return undefined;
    if (attempted[step] || touched[key]) return stepErrors[key];
    return undefined;
  };

  const announce = (next: StepIndex) =>
    setStepAnnounce(
      `ステップ ${next + 1} / 4、${STEP_TITLES[next]}。${STEP_DESCRIPTIONS[next]}`
    );

  const goToStep = (next: StepIndex) => {
    setStep(next);
    announce(next);
    // Move focus to the step heading so SR users land in the new step.
    requestAnimationFrame(() => {
      document.getElementById("step-heading")?.focus();
    });
  };

  const handleNext = () => {
    const errs = validateStep(step, form);
    setAttempted((a) => ({ ...a, [step]: true }));
    if (Object.keys(errs).length > 0) {
      const focusId = firstErrorFieldId(step, errs);
      if (focusId) {
        requestAnimationFrame(() => {
          const el = document.getElementById(focusId);
          el?.focus();
          el?.scrollIntoView({ block: "center", behavior: "smooth" });
        });
      }
      return; // blocked
    }
    if (step < 3) goToStep((step + 1) as StepIndex);
  };

  const handleBack = () => {
    if (step > 0) {
      // No validation on back.
      const prev = (step - 1) as StepIndex;
      setStep(prev);
      announce(prev);
      requestAnimationFrame(() => {
        document.getElementById("step-heading")?.focus();
      });
    }
  };

  const jumpToEdit = (target: StepIndex) => goToStep(target);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (step !== 3) {
      handleNext();
      return;
    }
    const errs = validateStep(3, form);
    setAttempted((a) => ({ ...a, 3: true }));
    if (Object.keys(errs).length > 0) {
      const focusId = firstErrorFieldId(3, errs);
      if (focusId)
        requestAnimationFrame(() => document.getElementById(focusId)?.focus());
      return;
    }
    setSubmitted(true);
  };

  const stepperSteps: StepperStep[] = STEP_TITLES.map((label, i) => ({
    label,
    state: i < step ? "completed" : i === step ? "current" : "upcoming",
  }));

  /* ----- success screen ----- */
  if (submitted) {
    return (
      <main className="mx-auto flex w-full max-w-2xl flex-1 flex-col items-center justify-center gap-6 px-4 py-12">
        <h1 className="sr-only">ワークスペースを作成しました</h1>
        <Alert variant="success" className="max-w-md">
          <AlertTitle>ワークスペースを作成しました</AlertTitle>
          <AlertDescription>
            {form.fullName.split(" ")[0] || "ようこそ"}さん、ようこそ。{" "}
            <strong>{form.company}</strong> のワークスペースが準備できました。
          </AlertDescription>
        </Alert>
        <Button variant="outline" onClick={() => { setSubmitted(false); goToStep(0); setForm(initialForm); }}>
          最初からやり直す
        </Button>
      </main>
    );
  }

  return (
    <main className="mx-auto flex w-full max-w-2xl flex-1 flex-col gap-6 px-4 py-8 sm:py-12">
      <header className="flex flex-col gap-1">
        <h1 className="text-2xl font-semibold tracking-tight">
          ワークスペースを作成
        </h1>
        <p className="text-sm text-muted-foreground">
          4つの簡単なステップでチームをセットアップしましょう。
        </p>
      </header>

      {/* Progress */}
      <div className="overflow-x-auto">
        <Stepper steps={stepperSteps} className="px-0" aria-label="セットアップの進捗" />
      </div>

      {/* SR-only live region announcing step changes */}
      <div aria-live="polite" className="sr-only">
        {stepAnnounce}
      </div>

      <Card>
        <CardHeader>
          <p className="text-xs font-medium text-muted-foreground">
            ステップ {step + 1} / 4
          </p>
          <CardTitle
            as="h2"
            id="step-heading"
            tabIndex={-1}
            className="outline-none"
          >
            {STEP_TITLES[step]}
          </CardTitle>
          <CardDescription>{STEP_DESCRIPTIONS[step]}</CardDescription>
        </CardHeader>

        <CardContent>
          <Form onSubmit={handleSubmit} noValidate>
            {/* ---------------- Step 1: Account ---------------- */}
            {step === 0 && (
              <>
                <FieldShell
                  id="field-fullName"
                  label="氏名"
                  required
                  error={showError("fullName")}
                >
                  {(a) => (
                    <Input
                      {...a.aria}
                      value={form.fullName}
                      onChange={(e) => set("fullName", e.target.value)}
                      onBlur={() => markTouched("fullName")}
                      placeholder="山田 花子"
                      autoComplete="name"
                    />
                  )}
                </FieldShell>

                <FieldShell
                  id="field-email"
                  label="仕事用メールアドレス"
                  required
                  error={showError("email")}
                >
                  {(a) => (
                    <Input
                      {...a.aria}
                      type="email"
                      value={form.email}
                      onChange={(e) => set("email", e.target.value)}
                      onBlur={() => markTouched("email")}
                      placeholder="you@company.com"
                      autoComplete="email"
                    />
                  )}
                </FieldShell>

                <FieldShell
                  id="field-password"
                  label="パスワード"
                  required
                  description={`${PASSWORD_MIN}文字以上で入力してください。`}
                  error={showError("password")}
                >
                  {(a) => (
                    <PasswordInput
                      {...a.aria}
                      // PasswordInput has no aria-invalid: styling — add a manual
                      // error ring on the wrapper so the error is visible too.
                      className={
                        showError("password")
                          ? "rounded-lg ring-1 ring-destructive-border"
                          : undefined
                      }
                      value={form.password}
                      onChange={(e) => set("password", e.target.value)}
                      onBlur={() => markTouched("password")}
                      placeholder="••••••••"
                      autoComplete="new-password"
                    />
                  )}
                </FieldShell>
              </>
            )}

            {/* ---------------- Step 2: Organization ---------------- */}
            {step === 1 && (
              <>
                <FieldShell
                  id="field-company"
                  label="会社名"
                  required
                  error={showError("company")}
                >
                  {(a) => (
                    <Input
                      {...a.aria}
                      value={form.company}
                      onChange={(e) => set("company", e.target.value)}
                      onBlur={() => markTouched("company")}
                      placeholder="株式会社あおぞら工房"
                      autoComplete="organization"
                    />
                  )}
                </FieldShell>

                <FieldShell
                  id="field-companySize"
                  label="会社規模"
                  required
                  error={showError("companySize")}
                >
                  {(a) => (
                    <RadioGroup
                      aria-labelledby={a.labelId}
                      aria-invalid={a.aria["aria-invalid"]}
                      aria-describedby={a.aria["aria-describedby"]}
                      aria-required={a.aria["aria-required"]}
                      value={form.companySize}
                      onValueChange={(v) => {
                        set("companySize", v);
                        markTouched("companySize");
                      }}
                      className="grid grid-cols-1 gap-2 sm:grid-cols-2"
                      id={a.id}
                    >
                      {COMPANY_SIZES.map((opt) => (
                        <label
                          key={opt.value}
                          className="flex cursor-pointer items-center gap-2 rounded-lg border border-border px-3 py-2 text-sm has-[[aria-checked=true]]:border-foreground"
                        >
                          <RadioGroupItem value={opt.value} />
                          <span>{opt.label}</span>
                        </label>
                      ))}
                    </RadioGroup>
                  )}
                </FieldShell>

                <FieldShell
                  id="field-industry"
                  label="業種"
                  required
                  error={showError("industry")}
                >
                  {(a) => (
                    <Select
                      {...a.aria}
                      // Select has no aria-invalid: styling — add a manual ring.
                      className={
                        showError("industry")
                          ? "ring-1 ring-destructive-border"
                          : undefined
                      }
                      value={form.industry}
                      onChange={(e) => {
                        set("industry", e.target.value);
                        markTouched("industry");
                      }}
                      onBlur={() => markTouched("industry")}
                    >
                      <option value="" disabled>
                        業種を選択…
                      </option>
                      {INDUSTRIES.map((opt) => (
                        <option key={opt.value} value={opt.value}>
                          {opt.label}
                        </option>
                      ))}
                    </Select>
                  )}
                </FieldShell>
              </>
            )}

            {/* ---------------- Step 3: Preferences ---------------- */}
            {step === 2 && (
              <>
                <FormField className="p-0">
                  <span className="text-sm font-medium leading-none text-foreground">
                    通知
                  </span>
                  <div className="flex flex-col gap-3 pt-1">
                    <Switch
                      checked={form.productUpdates}
                      onCheckedChange={(v) => set("productUpdates", v)}
                      label="製品アップデート"
                      description="新機能や改善に関するお知らせ。"
                    />
                    <Switch
                      checked={form.betaFeatures}
                      onCheckedChange={(v) => set("betaFeatures", v)}
                      label="ベータ機能"
                      description="試験的な機能をいち早く利用できます。"
                    />
                  </div>
                </FormField>

                <Checkbox
                  checked={form.shareUsage}
                  onCheckedChange={(v) => set("shareUsage", v)}
                  label="匿名の利用データを共有する"
                  description="製品の改善に役立てます。任意です。"
                />

                <FormField className="p-0">
                  <span
                    id="freq-label"
                    className="text-sm font-medium leading-none text-foreground"
                  >
                    通知の頻度
                  </span>
                  <RadioGroup
                    aria-labelledby="freq-label"
                    value={form.frequency}
                    onValueChange={(v) => set("frequency", v)}
                    className="grid gap-2 pt-1"
                  >
                    {FREQUENCIES.map((opt) => (
                      <label
                        key={opt.value}
                        className="flex cursor-pointer items-start gap-2 rounded-lg border border-border px-3 py-2 text-sm has-[[aria-checked=true]]:border-foreground"
                      >
                        <RadioGroupItem value={opt.value} className="mt-0.5" />
                        <span className="flex flex-col">
                          <span className="font-medium">{opt.label}</span>
                          <span className="text-xs text-muted-foreground">
                            {opt.hint}
                          </span>
                        </span>
                      </label>
                    ))}
                  </RadioGroup>
                </FormField>

                <FieldShell
                  id="field-goals"
                  label="どんなことを実現したいですか？"
                  description="任意 — セットアップを最適化するために役立てます。"
                >
                  {(a) => (
                    <Textarea
                      {...a.aria}
                      className="h-24 w-full"
                      value={form.goals}
                      onChange={(e) => set("goals", e.target.value)}
                      placeholder="例：チームのプロジェクトを一元管理したい…"
                    />
                  )}
                </FieldShell>
              </>
            )}

            {/* ---------------- Step 4: Review ---------------- */}
            {step === 3 && (
              <div className="flex flex-col gap-5">
                <ReviewSection
                  title="アカウント"
                  onEdit={() => jumpToEdit(0)}
                  rows={[
                    ["氏名", form.fullName],
                    ["仕事用メールアドレス", form.email],
                    ["パスワード", "•".repeat(Math.min(form.password.length, 12))],
                  ]}
                />
                <Separator />
                <ReviewSection
                  title="組織"
                  onEdit={() => jumpToEdit(1)}
                  rows={[
                    ["会社名", form.company],
                    [
                      "会社規模",
                      COMPANY_SIZES.find((s) => s.value === form.companySize)
                        ?.label ?? "—",
                    ],
                    [
                      "業種",
                      INDUSTRIES.find((s) => s.value === form.industry)?.label ??
                        "—",
                    ],
                  ]}
                />
                <Separator />
                <ReviewSection
                  title="設定"
                  onEdit={() => jumpToEdit(2)}
                  rows={[
                    [
                      "通知",
                      [
                        form.productUpdates && "製品アップデート",
                        form.betaFeatures && "ベータ機能",
                      ]
                        .filter(Boolean)
                        .join("、") || "なし",
                    ],
                    ["利用データ", form.shareUsage ? "共有する" : "共有しない"],
                    [
                      "頻度",
                      FREQUENCIES.find((f) => f.value === form.frequency)
                        ?.label ?? "—",
                    ],
                    ["目標", form.goals.trim() || "—"],
                  ]}
                />
                <Separator />

                <div className="flex flex-col gap-1.5">
                  <Checkbox
                    id="field-agreeTerms"
                    checked={form.agreeTerms}
                    onCheckedChange={(v) => {
                      set("agreeTerms", v);
                      markTouched("agreeTerms");
                    }}
                    aria-invalid={showError("agreeTerms") ? true : undefined}
                    aria-describedby={
                      showError("agreeTerms") ? "field-agreeTerms-error" : undefined
                    }
                    aria-required
                    label={
                      <span>
                        <span className="underline">利用規約</span>および{" "}
                        <span className="underline">プライバシーポリシー</span>に同意します。
                        <span className="ml-0.5 text-destructive" aria-hidden>
                          *
                        </span>
                      </span>
                    }
                  />
                  {showError("agreeTerms") ? (
                    <FormMessage id="field-agreeTerms-error" role="alert">
                      {showError("agreeTerms")}
                    </FormMessage>
                  ) : null}
                </div>
              </div>
            )}
          </Form>
        </CardContent>

        <CardFooter className="justify-between">
          <Button
            type="button"
            variant="outline"
            onClick={handleBack}
            disabled={step === 0}
          >
            戻る
          </Button>
          {step < 3 ? (
            <Button type="button" onClick={handleNext}>
              次へ
            </Button>
          ) : (
            <Button type="button" onClick={(e) => handleSubmit(e)}>
              ワークスペースを作成
            </Button>
          )}
        </CardFooter>
      </Card>

      <p className="text-center text-xs text-muted-foreground">
        ステップ {step + 1} / 4 ·{" "}
        <Badge as="span" variant="secondary">
          {Math.round(((step + 1) / 4) * 100)}% 完了
        </Badge>
      </p>
    </main>
  );
}

/* ------------------------------------------------------------------ */
/* Review section                                                     */
/* ------------------------------------------------------------------ */

function ReviewSection({
  title,
  rows,
  onEdit,
}: {
  title: string;
  rows: [string, React.ReactNode][];
  onEdit: () => void;
}) {
  return (
    <section aria-label={title} className="flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold">{title}</h3>
        <Button
          type="button"
          variant="ghost"
          size="sm"
          onClick={onEdit}
          aria-label={`${title}を編集`}
        >
          <IconPencil className="mr-1 h-3.5 w-3.5" />
          編集
        </Button>
      </div>
      <dl className="grid grid-cols-[auto_1fr] gap-x-4 gap-y-1 text-sm">
        {rows.map(([k, v]) => (
          <React.Fragment key={k}>
            <dt className="text-muted-foreground">{k}</dt>
            <dd className="break-words text-right font-medium sm:text-left">
              {v}
            </dd>
          </React.Fragment>
        ))}
      </dl>
    </section>
  );
}
